import { useCallback, useEffect, useState } from "react";
import { addCustomer, getCustomerHistory, getCustomers } from "../services/api";
import "../css/Customers.css";

function Customers() {
  const [customers, setCustomers] = useState([]);
  const [searchPhone, setSearchPhone] = useState("");
  const [formData, setFormData] = useState({ name: "", phone: "", address: "" });
  const [alertMessage, setAlertMessage] = useState("");
  const [alertType, setAlertType] = useState("success");
  const [selectedHistory, setSelectedHistory] = useState(null);

  const loadCustomers = useCallback(async (phone = "") => {
    try {
      const response = await getCustomers(phone);
      setCustomers(response.data || []);
    } catch (error) {
      setCustomers([]);
    }
  }, []);

  useEffect(() => {
    loadCustomers(searchPhone);
  }, [loadCustomers, searchPhone]);

  const handleFormChange = (event) => {
    const { name, value } = event.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleAddCustomer = async (event) => {
    event.preventDefault();
    setAlertMessage("");

    if (!formData.name || !formData.phone || !formData.address) {
      setAlertType("danger");
      setAlertMessage("Name, phone and address are required.");
      return;
    }

    if (!/^[0-9]{10}$/.test(formData.phone.trim())) {
      setAlertType("danger");
      setAlertMessage("Phone number must be exactly 10 digits.");
      return;
    }

    try {
      await addCustomer({
        name: formData.name.trim(),
        phone: formData.phone.trim(),
        address: formData.address.trim(),
      });
      setAlertType("success");
      setAlertMessage("Customer added successfully.");
      setFormData({ name: "", phone: "", address: "" });
      loadCustomers(searchPhone);
    } catch (error) {
      setAlertType("danger");
      setAlertMessage(error.response?.data?.message || "Failed to add customer.");
    }
  };

  const handleViewHistory = async (id) => {
    try {
      const response = await getCustomerHistory(id);
      setSelectedHistory(response.data);
    } catch (error) {
      setSelectedHistory(null);
    }
  };

  return (
    <section className="customers-page">
      <div className="container-fluid">
        <section className="customers-header mb-4">
          <h2 className="customers-title">Customer Management</h2>
          <p className="customers-subtitle">Store details, monitor purchases, and view history.</p>
        </section>

        <section className="customers-form-card card border-0 shadow-sm mb-4">
          <div className="card-body">
            {alertMessage && <div className={`alert alert-${alertType} mb-3`}>{alertMessage}</div>}
            <form className="row g-3" onSubmit={handleAddCustomer}>
              <div className="col-md-4">
                <label htmlFor="name" className="form-label">
                  Customer Name
                </label>
                <input
                  id="name"
                  type="text"
                  name="name"
                  className="form-control"
                  value={formData.name}
                  onChange={handleFormChange}
                  placeholder="Enter customer name"
                />
              </div>
              <div className="col-md-3">
                <label htmlFor="phone" className="form-label">
                  Phone Number
                </label>
                <input
                  id="phone"
                  type="text"
                  name="phone"
                  className="form-control"
                  value={formData.phone}
                  onChange={handleFormChange}
                  placeholder="Enter phone number"
                  maxLength="10"
                />
              </div>
              <div className="col-md-3">
                <label htmlFor="address" className="form-label">
                  Address
                </label>
                <input
                  id="address"
                  type="text"
                  name="address"
                  className="form-control"
                  value={formData.address}
                  onChange={handleFormChange}
                  placeholder="Enter address"
                />
              </div>
              <div className="col-md-2 d-flex align-items-end">
                <button type="submit" className="btn add-customer-btn w-100">
                  Add
                </button>
              </div>
            </form>
          </div>
        </section>

        <section className="customers-list-card card border-0 shadow-sm">
          <div className="card-body">
            <div className="row g-3 align-items-center mb-3">
              <div className="col-md-8">
                <input
                  type="text"
                  className="form-control customer-search-input"
                  placeholder="Search by 10-digit phone number"
                  value={searchPhone}
                  onChange={(event) => setSearchPhone(event.target.value)}
                />
              </div>
              <div className="col-md-4 text-md-end">
                <p className="result-count mb-0">{customers.length} result(s)</p>
              </div>
            </div>

            <div className="table-responsive">
              <table className="table align-middle customers-table mb-0">
                <thead>
                  <tr>
                    <th>Name</th>
                    <th>Phone</th>
                    <th>Address</th>
                    <th>Total Purchases</th>
                    <th>Action</th>
                  </tr>
                </thead>
                <tbody>
                  {customers.length === 0 ? (
                    <tr>
                      <td colSpan="5" className="text-center py-4">
                        No customers found.
                      </td>
                    </tr>
                  ) : (
                    customers.map((customer) => (
                      <tr key={customer._id}>
                        <td>{customer.name}</td>
                        <td>{customer.phone}</td>
                        <td>{customer.address}</td>
                        <td>Rs {Number(customer.totalPurchases || 0).toLocaleString("en-IN")}</td>
                        <td>
                          <button
                            type="button"
                            className="btn btn-sm history-btn"
                            onClick={() => handleViewHistory(customer._id)}
                          >
                            Purchase History
                          </button>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </section>

        <section className="customers-history-card card border-0 shadow-sm mt-4">
          <div className="card-body">
            <h5 className="history-title">Purchase History</h5>
            {selectedHistory ? (
              <div className="table-responsive">
                <table className="table align-middle mb-0">
                  <thead>
                    <tr>
                      <th>Invoice No</th>
                      <th>Date</th>
                      <th>Amount</th>
                    </tr>
                  </thead>
                  <tbody>
                    {selectedHistory.invoices.length ? (
                      selectedHistory.invoices.map((invoice) => (
                        <tr key={invoice._id}>
                          <td>{invoice.invoiceNumber}</td>
                          <td>{new Date(invoice.createdAt).toLocaleDateString("en-IN")}</td>
                          <td>Rs {Number(invoice.totalAmount).toLocaleString("en-IN")}</td>
                        </tr>
                      ))
                    ) : (
                      <tr>
                        <td colSpan="3" className="text-center py-3">
                          No purchases for this customer.
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            ) : (
              <p className="empty-history">Choose a customer to view purchase history.</p>
            )}
          </div>
        </section>
      </div>
    </section>
  );
}

export default Customers;
